import { mkdir, readdir, writeFile } from "node:fs/promises";
import path from "node:path";

import { CONFERENCES } from "../src/lib/conferences.ts";
import { CONFERENCE_ROUTE_DEFINITIONS } from "../src/lib/routes.ts";

const publicDir = "public";
const dataRootDir = path.join(publicDir, "ht");
const SITE_ORIGIN = "https://info.defcon.org";
const generatedHeader =
  "<!-- This file is generated by scripts/generate-public-indexes.mjs from src/lib/conferences.ts. Do not edit by hand. -->";
const generatedTextNotice =
  "> Generated by scripts/generate-public-indexes.mjs from src/lib/conferences.ts. Do not edit by hand.";

const PUBLIC_CONFERENCE_ALIASES = [
  {
    slug: "dc34",
    canonicalSlug: "defcon34",
  },
];

const organizationBackedSiteMenuKeys = new Set([
  "communities",
  "contests",
  "departments",
  "exhibitors",
  "vendors",
  "villages",
]);

const primaryFiles = [
  ["manifest.json", "Manifest JSON"],
  ["entities/events.json", "Schedule JSON"],
  ["entities/people.json", "People JSON"],
  ["entities/locations.json", "Locations JSON"],
  ["entities/organizations.json", "Organizations JSON"],
  ["views/searchData.json", "Search index JSON"],
];

const humanPages = [
  ["", "home"],
  ["schedule", "Schedule"],
  ["people", "Speakers and people"],
  ["locations", "Locations"],
  ["villages", "Villages"],
  ["search", "Search"],
];

const siteMenuLabels = new Map([
  ["announcements", "announcements"],
  ["bookmarks", "bookmarks"],
  ["communities", "communities"],
  ["content", "content"],
  ["contests", "contests"],
  ["departments", "departments"],
  ["exhibitors", "exhibitors"],
  ["locations", "locations"],
  ["maps", "maps"],
  ["merch", "merch"],
  ["people", "speakers and people"],
  ["readme", "readme"],
  ["schedule", "schedule"],
  ["search", "search"],
  ["vendors", "vendors"],
  ["villages", "villages"],
]);

const conferenceRoutesByKey = new Map(
  CONFERENCE_ROUTE_DEFINITIONS.map((route) => [route.key, route]),
);

const labelOverrides = new Map([
  ["derived/tagIdsByLabel.json", "Tag IDs by label JSON"],
  ["entities/articles.json", "Articles JSON"],
  ["entities/content.json", "Content JSON"],
  ["entities/documents.json", "Documents JSON"],
  ["entities/tags.json", "Tags JSON"],
  ["indexes/eventsByDay.json", "Events by day index JSON"],
  ["indexes/eventsByTag.json", "Events by tag index JSON"],
  ["views/contentCards.json", "Content cards JSON"],
  ["views/documentsList.json", "Documents list JSON"],
  ["views/organizationsCards.json", "Organization cards JSON"],
  ["views/peopleCards.json", "People cards JSON"],
  ["views/tagTypesBrowse.json", "Tag browse JSON"],
]);

function escapeHtml(value) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function escapeXml(value) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&apos;");
}

function routeHref(...segments) {
  const route = segments.filter(Boolean).join("/");

  return route ? `/${route}` : "/";
}

function dataHref(conference, relativePath) {
  return `${conference.dataRoot}/${relativePath}`;
}

function absoluteUrl(pathname) {
  return `${SITE_ORIGIN}${pathname}`;
}

function titleCaseIdentifier(value) {
  return value
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replace(/[-_]/g, " ")
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function labelForFile(relativePath) {
  return (
    labelOverrides.get(relativePath) ??
    `${titleCaseIdentifier(path.basename(relativePath, ".json"))} JSON`
  );
}

function wrapText(text, indent, maxLineLength = 100) {
  const width = maxLineLength - indent.length;
  const words = text.split(" ");
  const lines = [];
  let line = "";

  for (const word of words) {
    const candidate = line ? `${line} ${word}` : word;

    if (candidate.length > width && line) {
      lines.push(`${indent}${line}`);
      line = word;
      continue;
    }

    line = candidate;
  }

  if (line) {
    lines.push(`${indent}${line}`);
  }

  return lines.join("\n");
}

function renderParagraph(text) {
  return `      <p>
${wrapText(text, "        ")}
      </p>`;
}

function renderAlternateLink(href) {
  const escapedHref = escapeHtml(href);
  const line = `    <link rel="alternate" type="application/json" href="${escapedHref}" />`;

  if (line.length <= 100) {
    return line;
  }

  return `    <link
      rel="alternate"
      type="application/json"
      href="${escapedHref}"
    />`;
}

async function listJsonFiles(directory, prefix = "") {
  const entries = await readdir(directory, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    const relativePath = prefix ? `${prefix}/${entry.name}` : entry.name;
    const fullPath = path.join(directory, entry.name);

    if (entry.isDirectory()) {
      files.push(...(await listJsonFiles(fullPath, relativePath)));
      continue;
    }

    if (entry.isFile() && entry.name.endsWith(".json")) {
      files.push(relativePath);
    }
  }

  return files.toSorted((left, right) => left.localeCompare(right));
}

function renderLinks(items, makeHref) {
  return items
    .map(([relativePath, label]) => {
      const href = makeHref(relativePath);
      const line = `        <li><a href="${escapeHtml(href)}">${escapeHtml(label)}</a></li>`;

      if (line.length <= 100) {
        return line;
      }

      return `        <li>
          <a href="${escapeHtml(href)}">${escapeHtml(label)}</a>
        </li>`;
    })
    .join("\n");
}

function renderDataIndex(conference, jsonFiles) {
  const jsonFileSet = new Set(jsonFiles);
  const primaryItems = primaryFiles.filter(([relativePath]) => jsonFileSet.has(relativePath));
  const primaryPathSet = new Set(primaryItems.map(([relativePath]) => relativePath));
  const supportingItems = jsonFiles
    .filter((relativePath) => !primaryPathSet.has(relativePath))
    .map((relativePath) => [relativePath, labelForFile(relativePath)]);
  const title = `${conference.name} Machine-Readable Data`;
  const canonicalUrl = `${SITE_ORIGIN}/${conference.slug}/data/`;

  return `<!doctype html>
${generatedHeader}
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <meta
      name="description"
      content="Machine-readable ${escapeHtml(conference.name)} schedule data endpoints for AI agents, crawlers, and search systems."
    />
    <link rel="canonical" href="${escapeHtml(canonicalUrl)}" />
    <link rel="alternate" type="text/plain" href="/llms.txt" />
${primaryItems
  .map(([relativePath]) => renderAlternateLink(dataHref(conference, relativePath)))
  .join("\n")}
    <link rel="sitemap" type="application/xml" href="/sitemap.xml" />
    <title>${escapeHtml(title)}</title>
  </head>
  <body>
    <main>
      <h1>${escapeHtml(title)}</h1>

${renderParagraph(
  `${escapeHtml(conference.name)} data is published as static JSON and fetched by the web app at runtime. These JSON files are the authoritative sources for agents, crawlers, and search systems. Files may be replaced as conference information changes without rebuilding the site.`,
)}

      <h2>Primary Endpoints</h2>
      <ul>
${renderLinks(primaryItems, (relativePath) => dataHref(conference, relativePath))}
      </ul>

      <h2>Supporting Data</h2>
      <ul>
${renderLinks(supportingItems, (relativePath) => dataHref(conference, relativePath))}
      </ul>

      <h2>Structure</h2>
${renderParagraph(
  `Data lives under <code>${escapeHtml(`${conference.dataRoot}/`)}</code>. Entity files contain canonical records, index files map relationships for navigation, view files are precomputed lists for the client UI, and derived files provide app metadata.`,
)}

      <h2>Human Pages</h2>
      <ul>
${renderLinks(
  humanPages.map(([segment, label]) => [segment, segment ? label : `${conference.name} home`]),
  (segment) => routeHref(conference.slug, segment),
)}
      </ul>
    </main>
  </body>
</html>
`;
}

function renderAliasIndex(conference) {
  const canonicalPath = routeHref(conference.slug, "data") + "/";
  const canonicalUrl = `${SITE_ORIGIN}${canonicalPath}`;
  const title = `${conference.name} data guide moved`;

  return `<!doctype html>
${generatedHeader}
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <meta
      name="description"
      content="Compatibility page for the ${escapeHtml(conference.name)} machine-readable data guide."
    />
    <meta http-equiv="refresh" content="0; url=${escapeHtml(canonicalPath)}" />
    <link rel="canonical" href="${escapeHtml(canonicalUrl)}" />
    <title>${escapeHtml(title)}</title>
  </head>
  <body>
    <main>
      <h1>${escapeHtml(title)}</h1>
      <p><a href="${escapeHtml(canonicalPath)}">Open the ${escapeHtml(conference.name)} data guide.</a></p>
    </main>
  </body>
</html>
`;
}

async function writeGeneratedFile(routeSlug, html) {
  const directory = path.join(publicDir, routeSlug, "data");

  await mkdir(directory, { recursive: true });
  await writeFile(path.join(directory, "index.html"), html, "utf8");
}

function hasOrganizationBackedSection(conference) {
  return conference.siteMenu.some((key) => organizationBackedSiteMenuKeys.has(key));
}

function renderLlmsJsonDataLinks(conference) {
  const lines = [
    `- ${conference.name} manifest: ${absoluteUrl(dataHref(conference, "manifest.json"))}`,
    `- ${conference.name} schedule events: ${absoluteUrl(
      dataHref(conference, "entities/events.json"),
    )}`,
    `- ${conference.name} speakers and people: ${absoluteUrl(
      dataHref(conference, "entities/people.json"),
    )}`,
  ];

  if (conference.siteMenu.includes("locations")) {
    lines.push(
      `- ${conference.name} locations: ${absoluteUrl(
        dataHref(conference, "entities/locations.json"),
      )}`,
    );
  }

  if (hasOrganizationBackedSection(conference)) {
    lines.push(
      `- ${conference.name} organizations: ${absoluteUrl(
        dataHref(conference, "entities/organizations.json"),
      )}`,
    );
  }

  lines.push(
    `- ${conference.name} search index: ${absoluteUrl(dataHref(conference, "views/searchData.json"))}`,
    `- ${conference.name} data guide: ${absoluteUrl(routeHref(conference.slug, "data"))}/`,
  );

  return lines.join("\n");
}

function renderLlmsHumanLinks(conference) {
  const lines = [
    `- ${conference.name}: ${absoluteUrl(routeHref(conference.slug))}`,
    `- ${conference.name} data guide: ${absoluteUrl(routeHref(conference.slug, "data"))}/`,
  ];

  for (const key of conference.siteMenu) {
    const label = siteMenuLabels.get(key);
    const route = conferenceRoutesByKey.get(key);

    if (!label || !route) {
      continue;
    }

    lines.push(
      `- ${conference.name} ${label}: ${absoluteUrl(
        routeHref(conference.slug, route.staticSegment),
      )}`,
    );
  }

  return lines.join("\n");
}

function renderLlmsAliases() {
  if (PUBLIC_CONFERENCE_ALIASES.length === 0) {
    return "";
  }

  return `## Aliases

${PUBLIC_CONFERENCE_ALIASES.map((alias) => {
  const conference = CONFERENCES[alias.canonicalSlug];

  if (!conference) {
    throw new Error(
      `Unknown canonical conference slug for alias ${alias.slug}: ${alias.canonicalSlug}`,
    );
  }

  return `- ${conference.name} data guide alias: ${absoluteUrl(
    routeHref(alias.slug, "data"),
  )}/ canonical: ${absoluteUrl(routeHref(conference.slug, "data"))}/`;
}).join("\n")}`;
}

function renderLlmsTxt(conferences) {
  const aliasesSection = renderLlmsAliases();
  const sections = [
    `# info.defcon.org

${generatedTextNotice}

info.defcon.org is the static-first DEF CON conference information site. It provides human pages for conference schedules, speakers, locations, villages, search, and related reference information.

The browser app fetches conference data from JSON at runtime. These JSON files are the authoritative canonical data sources and may be replaced independently of a site rebuild.

## Canonical JSON Data

${conferences.map((conference) => renderLlmsJsonDataLinks(conference)).join("\n\n")}

## Human Pages

- Site home: ${absoluteUrl("/")}
- Conferences: ${absoluteUrl("/conferences")}
${conferences.map((conference) => renderLlmsHumanLinks(conference)).join("\n")}`,
    aliasesSection,
    `## Discovery

- Sitemap: ${absoluteUrl("/sitemap.xml")}
- Robots: ${absoluteUrl("/robots.txt")}

Prefer the JSON endpoints above for machine-readable conference data. Human pages are client-rendered and may summarize or navigate the same runtime data.`,
  ].filter(Boolean);

  return `${sections.join("\n\n")}\n`;
}

function sitemapUrl(pathname) {
  return `  <url>
    <loc>${escapeXml(absoluteUrl(pathname))}</loc>
  </url>`;
}

function sitemapConferencePaths(conference) {
  const paths = [routeHref(conference.slug)];

  for (const key of conference.siteMenu) {
    const route = conferenceRoutesByKey.get(key);

    if (!route || !route.staticSegment) {
      continue;
    }

    paths.push(routeHref(conference.slug, route.staticSegment));
  }

  paths.push(`${routeHref(conference.slug, "data")}/`);

  return paths;
}

function sitemapAliasPaths() {
  return PUBLIC_CONFERENCE_ALIASES.map((alias) => `${routeHref(alias.slug, "data")}/`);
}

function renderSitemapXml(conferences) {
  const paths = [
    "/",
    "/apps/",
    "/conferences",
    ...conferences.flatMap((conference) => sitemapConferencePaths(conference)),
    ...sitemapAliasPaths(),
  ];

  return `<?xml version="1.0" encoding="UTF-8"?>
${generatedHeader}
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
${paths.map((pathname) => sitemapUrl(pathname)).join("\n")}
</urlset>
`;
}

const generated = [];
const conferences = Object.values(CONFERENCES);

for (const conference of conferences) {
  const jsonFiles = await listJsonFiles(path.join(dataRootDir, conference.slug));

  await writeGeneratedFile(conference.slug, renderDataIndex(conference, jsonFiles));
  generated.push(`${conference.slug}/data/index.html`);
}

for (const alias of PUBLIC_CONFERENCE_ALIASES) {
  const conference = CONFERENCES[alias.canonicalSlug];

  if (!conference) {
    throw new Error(
      `Unknown canonical conference slug for alias ${alias.slug}: ${alias.canonicalSlug}`,
    );
  }

  await writeGeneratedFile(alias.slug, renderAliasIndex(conference));
  generated.push(`${alias.slug}/data/index.html`);
}

await writeFile(path.join(publicDir, "llms.txt"), renderLlmsTxt(conferences), "utf8");
generated.push("llms.txt");

await writeFile(path.join(publicDir, "sitemap.xml"), renderSitemapXml(conferences), "utf8");
generated.push("sitemap.xml");

console.log("Generated public indexes:");
for (const file of generated.toSorted((left, right) => left.localeCompare(right))) {
  console.log(`- public/${file}`);
}
